INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$No-code funnel builder$q$, $q$Drag-and-drop editor for combining quizzes, surveys, forms and calculators into multi-step interactive funnels.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$Conditional logic jumps$q$, $q$Branch respondents down different question or outcome paths based on their previous answers.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$300-plus templates$q$, $q$Pre-built templates for quizzes, ROI calculators, NPS surveys, giveaways and lead forms to speed up funnel creation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$Email automation$q$, $q$Trigger automated follow-up email sequences the moment a visitor completes a funnel.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$30-plus integrations$q$, $q$Native connections to Zapier, HubSpot, Mailchimp, ActiveCampaign, Google Sheets, Slack and webhooks.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$A/B testing and custom CSS$q$, $q$Test funnel variants and apply custom styling on the Scale and Enterprise plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$Analytics dashboard$q$, $q$Track completion rates, drop-off points and lead quality across every published funnel.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$SOC 2 and GDPR-compliant hosting$q$, $q$Paid plans run on audited, GDPR-compliant infrastructure with SSL encryption for all data transfer.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$Generous free plan lets teams test the funnel-building workflow before paying$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$Large template library speeds up building common funnel types like quizzes and calculators$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$Conditional logic allows genuinely personalized visitor journeys, not just static forms$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$SOC 2 Type II and GDPR compliance make it viable for larger, compliance-conscious teams$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$Bootstrapped, profitable company with a track record of steady feature releases$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$Free plan strips out integrations and logic jumps, the platform's most useful features$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$Enterprise pricing starts at $399/month and requires an annual contract$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$Submission and visit caps on lower tiers can be restrictive for higher-traffic sites$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$Design customization is more limited than dedicated page builders$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$Smaller integration ecosystem than category leaders like Typeform$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$What is involve.me used for?$q$, $q$involve.me is used to build interactive quizzes, surveys, forms and calculators that capture leads and qualify visitors before routing them into a follow-up email sequence or CRM.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$Does involve.me have a free plan?$q$, $q$Yes, involve.me offers a free plan with two live funnels, 50 submissions and 500 visits per month, though it lacks integrations, logic jumps and data export.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$Who founded involve.me?$q$, $q$involve.me was founded by Vlad Gozman in Vienna, Austria, launching in 2019 after pivoting from an earlier virtual-reality content tool.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$How much does involve.me cost?$q$, $q$Paid annual plans start at $19/month for Start, rising to $49/month for Grow and $119/month for Scale, with custom Enterprise pricing starting from $399/month.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$Is involve.me GDPR compliant?$q$, $q$Yes, involve.me's paid infrastructure is SOC 2 Type II-audited and GDPR-compliant, with SSL encryption for data in transit.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$What are the best alternatives to involve.me?$q$, $q$Common alternatives include Typeform, Outgrow, Jotform, Interact and Landbot, depending on whether the priority is quiz building, form design or conversational lead capture.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$Lead-qualifying quizzes$q$, $q$Marketing teams build scored or personality quizzes that segment visitors and route qualified leads to sales or a nurture sequence.$q$, $q$Marketing and growth teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$Pricing and ROI calculators$q$, $q$SaaS and service businesses embed interactive calculators on pricing pages to help prospects self-qualify and estimate value before booking a call.$q$, $q$B2B SaaS and services companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$Client campaign funnels$q$, $q$Agencies build and manage multiple branded funnels across client accounts using multi-user Scale or Enterprise plans.$q$, $q$Marketing agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$Free$q$, $q$$0$q$, $q$Free forever$q$, NULL, $q$["2 live funnels","50 submissions/month","500 visits/month","Access to templates","30-day data retention"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$Start$q$, $q$$19/month (annual) or $29/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["3 live funnels","1 user","Email automations and conditional logic","30-plus integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$Grow$q$, $q$$49/month (annual) or $69/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["5 live funnels","2 users","Remove branding","UTM parameters","1 custom domain"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$Scale$q$, $q$$119/month (annual) or $139/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["25 live funnels","5 users","A/B testing","Custom CSS","Webhooks"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$Enterprise$q$, $q$From $399/month$q$, $q$Annual contract only$q$, NULL, $q$["Custom funnel and user limits","Single sign-on","Security assessment","Dedicated onboarding"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$involve.me is a no-code SaaS platform built around a single idea: interactive content converts better than static landing pages. Instead of a plain contact form, businesses can build a scored quiz, an ROI calculator, or a multi-step survey that qualifies and segments visitors while collecting their contact details, then route each respondent down a different follow-up path based on how they answered.$q$, $q$The company was founded in Vienna, Austria by Vlad Gozman, who pivoted the product from an earlier, unsuccessful virtual-reality content tool into the interactive-funnel builder that launched in 2019. Since then involve.me has grown into a bootstrapped, profitable company serving thousands of businesses, from solo marketers to agencies running client campaigns, without taking on significant outside venture funding.$q$, $q$The platform is positioned squarely at marketing and growth teams rather than developers: everything from logic branching to integrations is configured through a visual editor, and the extensive template library is designed to get a funnel live within minutes rather than days.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At the core of involve.me is its funnel builder, which lets users combine quizzes, surveys, forms and calculators into a single multi-step flow with conditional logic jumps, so different answers lead to different questions, outcomes or offers. Funnels can be embedded on an existing site, deployed as standalone pages, or launched as on-site pop-ups, giving marketers flexibility in how they insert interactive content into an existing funnel.$q$, $q$Beyond content creation, involve.me includes built-in email automation, so a completed quiz or form can immediately trigger a follow-up sequence, plus a results dashboard for tracking completion rates, drop-off points and lead quality. Higher tiers unlock A/B testing, custom CSS styling, custom domains, and webhooks, while more than 30 native integrations (Zapier, HubSpot, Mailchimp, ActiveCampaign, Google Sheets and Slack among them) connect captured leads to a business's existing marketing stack.$q$, $q$Security and compliance are notable for a tool at this price point: involve.me's paid plans run on SOC 2 Type II-audited, GDPR-compliant infrastructure with 128-bit SSL encryption, and the Enterprise tier adds single sign-on and a dedicated security assessment, making the platform usable by larger organizations with procurement requirements.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d865b7df-50df-49c9-97ab-b4f5ff75a05c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$involve.me uses a freemium model. The Free plan supports two live funnels with 50 submissions and 500 visits per month, 30-day data retention, and access to the template library, but withholds integrations, logic jumps and data export. From there, annually billed plans start at Start ($19/month, 3 funnels, 1 user), move to Grow ($49/month, 5 funnels, 2 users, branding removal and a custom domain), and Scale ($119/month, 25 funnels, 5 users, A/B testing and webhooks), with an Enterprise tier starting from $399/month for custom limits, SSO and dedicated onboarding.$q$, $q$Monthly billing is available but costs noticeably more than the annual equivalent (for example Start is $29/month billed monthly versus $19/month billed annually), which is standard SaaS practice to reward annual commitments. Because pricing scales with both funnel count and team seats rather than raw traffic, small teams running a handful of funnels can typically stay on the Start or Grow tiers, while agencies managing many client campaigns tend to need Scale or a custom Enterprise agreement.$q$]::text[], 2);
