INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$1,000-plus adapters$q$, $q$Community-built plugins connect ioBroker to smart home protocols, voice assistants, media systems and industrial data sources.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$js-controller core$q$, $q$Central Node.js coordinator that manages adapter lifecycles and routes data through a shared object database.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$VIS visualization$q$, $q$Drag-and-drop dashboard builder for creating custom control panels viewable in any browser or on mobile.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$JavaScript and Blockly scripting$q$, $q$Write automation rules in native JavaScript or a visual Blockly editor without needing a full development environment.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$Self-hosted deployment$q$, $q$Runs on Raspberry Pi, Docker, Linux, Windows or macOS, keeping all device data on hardware the user controls.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$Multi-instance and multi-host support$q$, $q$Distribute adapters across multiple machines for redundancy or resource isolation.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$Web-based Admin interface$q$, $q$Install, configure and monitor adapters and system logs from a browser-based control panel.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$Broad protocol support$q$, $q$Native compatibility with KNX, Zigbee, Z-Wave, Homematic, MQTT, Modbus and OPC-UA among others.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$Core platform and most adapters are completely free and open source$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$Runs locally, keeping smart home data off third-party clouds$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$Enormous adapter library covers protocols and devices few competitors support$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$Lightweight Node.js footprint runs comfortably on a Raspberry Pi$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$Active, long-running German-language community with deep HomeMatic/KNX expertise$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$Steeper learning curve than consumer smart home hubs or Home Assistant for newcomers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$Documentation and community support skew toward German speakers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$Requires ongoing self-hosting and maintenance responsibility$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$Some adapters require a separate free license, adding friction$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$Smaller global community and adapter polish compared to Home Assistant$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$Is ioBroker free?$q$, $q$Yes, the ioBroker core and the vast majority of its adapters are free and open source under the MIT license. An optional paid ioBroker.pro cloud service is available for users who don't want to self-host.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$What hardware does ioBroker run on?$q$, $q$ioBroker runs on any device that supports Node.js with at least 1GB of RAM, including a Raspberry Pi, Docker container, Linux server, Windows PC or Mac.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$Who develops ioBroker?$q$, $q$ioBroker is maintained by developer Denis Haev ('Bluefox') through ioBroker GmbH, alongside a large community of volunteer adapter contributors.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$How is ioBroker different from Home Assistant?$q$, $q$Both are open-source, self-hosted home automation platforms, but ioBroker is built on Node.js/JavaScript with especially strong support for German building-automation standards like KNX and Homematic, while Home Assistant is Python-based with a larger global community.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$Does ioBroker support Zigbee and Z-Wave?$q$, $q$Yes, ioBroker has dedicated adapters for Zigbee and Z-Wave, alongside KNX, Homematic, MQTT, Modbus and many other protocols.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$Can ioBroker control voice assistants like Alexa?$q$, $q$Yes, ioBroker includes adapters for Amazon Alexa and Google Home, allowing voice control of connected devices.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$Whole-home smart automation$q$, $q$Hobbyists connect lighting, heating, sensors and voice assistants from different manufacturers into one automation layer.$q$, $q$Home automation enthusiasts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$Building and energy monitoring$q$, $q$Small integrators use Modbus and OPC-UA adapters to log and visualize energy consumption and building system data.$q$, $q$Building automation integrators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$Privacy-first smart home setups$q$, $q$Privacy-conscious users self-host ioBroker to keep device data off manufacturer clouds while still using voice assistants and mobile dashboards.$q$, $q$Privacy-conscious homeowners$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$Self-hosted (Open Source)$q$, $q$Free$q$, $q$One-time install, self-hosted$q$, NULL, $q$["js-controller core","1,000-plus community adapters","VIS dashboards","Local data storage"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$ioBroker.pro$q$, $q$Paid subscription (contact for pricing)$q$, $q$Subscription$q$, NULL, $q$["Hosted/cloud convenience layer","Remote access","Automated backups","Simplified server management"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ioBroker is a self-hosted, open-source platform for tying together smart home devices, building automation systems and IoT data sources that would otherwise live in separate, incompatible apps and clouds. Rather than shipping its own hardware, ioBroker runs as software on hardware the user already owns, most commonly a Raspberry Pi, a small home server, or a Docker container, and talks to devices through a large library of community-maintained adapters.$q$, $q$The project grew out of CCU.IO, an earlier tool built for Germany's HomeMatic smart-home ecosystem, and emerged as its own platform around 2014 under the leadership of developer Denis Haev ('Bluefox'), who continues to drive core development today through the small company ioBroker GmbH. Rather than raising venture funding, the project sustains itself through a combination of contract development work, an optional paid cloud add-on, and community contributions.$q$, $q$Because it runs entirely on infrastructure the user controls, ioBroker appeals strongly to privacy-conscious users who want smart home automation without routing device data through a manufacturer's cloud, and to hobbyists who want to combine devices from many different ecosystems -- KNX, Zigbee, Z-Wave, MQTT and more -- into a single automation layer.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At the center of ioBroker is the js-controller, a Node.js process that manages the lifecycle of every installed adapter and routes data between them through a shared object and state database. Adapters exist for well over a thousand devices and services, spanning smart home protocols (Zigbee, Z-Wave, KNX, Homematic), voice assistants (Alexa, Google Home), media systems (Sonos, Philips Hue), and industrial or energy-monitoring protocols (Modbus, OPC-UA, MQTT), which is what lets ioBroker act as a universal translation layer across otherwise siloed ecosystems.$q$, $q$Automation and visualization are handled through companion tools: the JavaScript/Blockly scripting adapter lets users write conditional automation rules (for example, dim the lights when a motion sensor and a light-level sensor both fire), while the VIS module provides a drag-and-drop dashboard builder for creating custom control panels viewable from a browser or mobile device.$q$, $q$Administration happens through a web-based Admin interface for installing adapters, configuring instances, and monitoring logs, and the entire system supports multi-instance and multi-host setups, so power users can spread ioBroker across several machines for redundancy or to isolate resource-heavy adapters.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('040370f5-8835-4009-88cd-4a1d8b345969', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The ioBroker core (js-controller) and the overwhelming majority of its adapters are free and open source under the MIT license, so a self-hosted installation costs nothing beyond the hardware it runs on. A small number of adapters, particularly ones tied to commercial third-party integrations, require a free license issued by ioBroker GmbH for private use, which is used mainly to gauge adoption rather than to charge users.$q$, $q$For users who don't want to manage their own server, ioBroker GmbH offers ioBroker.pro, a paid hosted/cloud convenience service that handles remote access and backups for a subscription fee. This keeps the underlying platform's cost model close to zero for self-hosters while giving the maintaining company a modest, sustainable revenue stream to fund ongoing development, distinct from a typical SaaS pricing ladder.$q$]::text[], 2);
