INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$One-shot mail server installer$q$, $q$Deploys Postfix, Dovecot, webmail and anti-spam tooling as a fully configured mail server via a single script.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$Choice of backend$q$, $q$Supports OpenLDAP, MySQL/MariaDB or PostgreSQL for storing domains, users and mailing lists.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$Roundcube and SOGo webmail/groupware$q$, $q$Browser-based email plus CalDAV calendars, CardDAV contacts and ActiveSync mobile sync via SOGo.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$Integrated anti-spam and anti-virus$q$, $q$SpamAssassin, ClamAV, Amavisd, SPF and OpenDKIM filter and authenticate mail out of the box.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$Fail2ban intrusion prevention$q$, $q$Automatically blocks IPs after repeated failed login attempts against mail services.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$Unlimited domains and mailboxes$q$, $q$No artificial caps on domains, users or mailing lists in the free, self-hosted edition.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$iRedAdmin-Pro admin panel$q$, $q$Optional paid, full-featured web admin panel with advanced quota management and reporting.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$Broad OS support$q$, $q$Installs on CentOS Stream, Rocky Linux, AlmaLinux, Debian, Ubuntu, FreeBSD and OpenBSD.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$Core mail server software is completely free and open source$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$Assembles a dozen normally-separate mail components into one secured stack$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$Unlimited domains, mailboxes and mailing lists with no per-seat fee$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$Long track record dating to 2007 with continuous active maintenance$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$Full data ownership since mail runs entirely on infrastructure the user controls$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$Requires comfort with Linux/BSD server administration and command-line setup$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$Free admin panel is intentionally limited compared to iRedAdmin-Pro$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$No official cloud-hosted version; self-hosting is the primary deployment model$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$Ongoing patching, backups and uptime are the administrator's responsibility$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$Documentation and support community skew toward experienced sysadmins$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$Is iRedMail free?$q$, $q$Yes, the core iRedMail installer and the mail server it deploys are free and open source under GPLv3. Optional paid add-ons, iRedAdmin-Pro and iRedMail Easy, are available for advanced administration and managed support.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$What mail components does iRedMail install?$q$, $q$iRedMail installs Postfix for SMTP, Dovecot for POP3/IMAP, Roundcube and/or SOGo for webmail and groupware, and SpamAssassin, ClamAV, Amavisd, SPF and OpenDKIM for anti-spam and security.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$What operating systems does iRedMail support?$q$, $q$iRedMail supports CentOS Stream, Rocky Linux, AlmaLinux, Debian, Ubuntu, FreeBSD and OpenBSD.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$Who created iRedMail?$q$, $q$iRedMail was created by developer Zhang Huangbin in November 2007 and has been actively maintained since.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$Does iRedMail support calendars and contacts?$q$, $q$Yes, when installed with the SOGo groupware component, iRedMail supports CalDAV calendars, CardDAV contacts and ActiveSync for mobile devices.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$What is iRedAdmin-Pro?$q$, $q$iRedAdmin-Pro is an optional, paid, full-featured web administration panel for iRedMail that adds advanced quota management and reporting beyond the free bundled admin panel.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$Self-hosted business email$q$, $q$Small businesses deploy iRedMail on their own server to run company email without paying per-mailbox SaaS fees.$q$, $q$Small businesses and startups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$Privacy-focused email hosting$q$, $q$Privacy-conscious organizations and individuals self-host mail to keep messages off third-party cloud providers.$q$, $q$Privacy-focused organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$Hosting provider mail infrastructure$q$, $q$Web hosts and ISPs use iRedMail as the base mail stack for reselling hosted mailboxes to their own customers.$q$, $q$Hosting providers and ISPs$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$Open Source Edition$q$, $q$Free$q$, $q$Self-hosted, free forever$q$, NULL, $q$["Unlimited domains and mailboxes","Postfix, Dovecot, Roundcube/SOGo","Anti-spam and anti-virus stack","Basic web admin panel"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$iRedAdmin-Pro$q$, $q$Paid license, renewal around $250/year$q$, $q$License plus annual renewal$q$, NULL, $q$["Advanced web admin panel","Per-domain reporting","Advanced quota management"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$iRedMail Easy$q$, $q$Around $499/year or $49/month (12-month plan)$q$, $q$Annual or 12-month subscription$q$, NULL, $q$["Guided hosted deployment assistance","Ongoing setup support","Managed maintenance guidance"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$iRedMail solves a specific, long-standing sysadmin problem: standing up a secure, full-featured mail server from open-source parts normally requires manually integrating a dozen separate projects -- an SMTP daemon, an IMAP server, a spam filter, an antivirus scanner, a webmail client and an authentication backend -- each with its own configuration quirks and security pitfalls. iRedMail packages that entire stack into a single guided installer script that produces a working, secured mail server in minutes rather than days.$q$, $q$Started in 2007 by developer Zhang Huangbin, the project has been continuously maintained for nearly two decades and supports a wide range of Linux and BSD distributions, making it one of the longest-running self-hosted mail server projects still in active development.$q$, $q$The base installer and resulting server are fully open source and free under GPLv3, with the project's commercial layer limited to an optional, more advanced admin panel and an optional managed-deployment support service, rather than gating the mail server itself behind a paywall.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$iRedMail's core stack pairs Postfix for SMTP with Dovecot for POP3/IMAP, backed by the administrator's choice of OpenLDAP, MySQL/MariaDB, or PostgreSQL for storing domains, users and mailing lists, giving organizations flexibility to match their existing directory infrastructure. On top of that base, Roundcube webmail and the SOGo groupware suite provide browser-based email, plus CalDAV/CardDAV calendars and contacts and ActiveSync for syncing with mobile devices.$q$, $q$Security is handled through a layered stack: Amavisd, SpamAssassin and ClamAV filter spam and malware, OpenDKIM and SPF authenticate outbound mail, Fail2ban blocks brute-force login attempts, and iRedAPD enforces custom Postfix sender/recipient policies. All client connections are forced over TLS by default, and captured spam is routed into a quarantine rather than silently dropped.$q$, $q$For administrators who need more than the bundled free admin panel offers, iRedAdmin-Pro adds features like per-domain reporting, advanced mailbox quota management, and a more polished management UI, while iRedMail Easy provides a hosted deployment assistant that walks less experienced users through provisioning and maintaining their own self-hosted server.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core iRedMail installer, and the full mail server it produces (unlimited domains, users, and mailing lists on Postfix, Dovecot, Roundcube/SOGo and the full anti-spam/antivirus stack) is completely free and open source under GPLv3, with no license fee for self-hosting on the administrator's own server.$q$, $q$Two optional paid products sit on top: iRedAdmin-Pro, the advanced admin panel, is sold as a license with a reported renewal fee around $250 per year for continued updates, and iRedMail Easy, a hosted setup and support platform aimed at less technical administrators, runs about $499 per year or $49 per month on a 12-month plan. Neither product is required to run a fully functional iRedMail server -- they exist purely to simplify administration or provide additional support for organizations willing to pay for it.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ba51550d-a30f-4ff6-991a-d6db68d152ca', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$Structured contract repository$q$, $q$Centralized, searchable repository that stores contracts with metadata, related documents and obligation tracking.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$No-code workflow designer$q$, $q$Build custom intake, approval and negotiation workflows without engineering support.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$Native e-signature$q$, $q$Sign contracts natively in Ironclad or route them through integrated e-signature tools like DocuSign.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$Ironclad Clickwrap$q$, $q$High-volume click-to-accept agreement tool for terms of service, NDAs and similar standard contracts.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$AI contract review and drafting$q$, $q$Generative AI redlines contracts against playbooks, extracts key terms and flags risk across the repository.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$Analytics and reporting$q$, $q$Dashboards tracking cycle time, approval bottlenecks and overall contract volume.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$Business system integrations$q$, $q$Pre-built connections to Salesforce, Slack, Microsoft and other tools business teams already use.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$Enterprise security$q$, $q$SOC 2-compliant infrastructure with advanced permissions suited to large organizations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$Deep, workflow-first contract automation built specifically for legal and business collaboration$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$Strong generative AI features for redlining, term extraction and risk flagging$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$Large integration ecosystem covering Salesforce, Slack and Microsoft tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$Well-funded, established vendor with over 1,000 customers and 2 billion contracts processed$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$Native e-signature plus Clickwrap covers both negotiated and high-volume standard agreements$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$Pricing is not published and requires a sales conversation, complicating budget planning$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$High cost relative to smaller CLM tools, with typical annual contracts in the tens of thousands of dollars$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$AI Assist and advanced modules are priced as separate add-ons on top of base licensing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$Implementation and integration work can add significant upfront cost and time$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$Primarily suited to mid-market and enterprise teams rather than very small legal departments$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$What is Ironclad used for?$q$, $q$Ironclad is a contract lifecycle management platform used to create, negotiate, sign, store and analyze contracts across legal, sales and procurement teams.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$Who founded Ironclad?$q$, $q$Ironclad was founded in 2014 by attorney Jason Boehmig and engineer Cai GoGwilt, launching out of Y Combinator in 2015.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$How much does Ironclad cost?$q$, $q$Ironclad does not publish pricing publicly; it sells through a custom sales process, with market data suggesting typical annual contracts range from about $30,000 to over $250,000.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$Does Ironclad have an AI feature?$q$, $q$Yes, Ironclad's AI Assist capabilities use generative AI to redline contracts against playbooks, extract key terms and flag risk, though this is often priced as a separate add-on.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$Who are Ironclad's main competitors?$q$, $q$Ironclad's main competitors include DocuSign CLM, Icertis, ContractPodAi, Agiloft, SirionLabs and Concord.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$Where is Ironclad headquartered?$q$, $q$Ironclad is headquartered in San Francisco, California, with an additional office in New York.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$Legal team contract automation$q$, $q$In-house legal departments centralize contract drafting, redlining and approvals to cut cycle time and reduce risk.$q$, $q$In-house legal teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$Sales agreement workflows$q$, $q$Sales operations teams route order forms and customer agreements through automated approval workflows tied to CRM data.$q$, $q$Sales operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$High-volume clickwrap agreements$q$, $q$Businesses use Ironclad Clickwrap to manage terms of service, NDAs and other standard agreements at scale without manual negotiation.$q$, $q$Enterprise procurement and legal operations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$Standard$q$, $q$Custom pricing (typically tens of thousands per year)$q$, $q$Annual contract$q$, NULL, $q$["Contract creation and management","Workflow automation","E-signature","Standard integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$Professional$q$, $q$Custom pricing$q$, $q$Annual contract$q$, NULL, $q$["All Standard features","Advanced analytics and reporting","Customizable workflows","Enhanced security and priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$Enterprise$q$, $q$Custom pricing (often $100,000-plus per year)$q$, $q$Annual contract$q$, NULL, $q$["All Professional features","Unlimited contract volume","Dedicated account manager","Advanced compliance and custom integrations"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Ironclad is built to replace the patchwork of email threads, shared drives and static templates that most legal and business teams historically used to manage contracts, offering instead a single structured repository where every contract's metadata, clauses, approvals and signature status are tracked and searchable. The platform is aimed primarily at in-house legal teams but extends workflow access to sales, procurement and other business functions that originate or need visibility into contracts.$q$, $q$Founded in 2014 by attorney Jason Boehmig and engineer Cai GoGwilt and launched out of Y Combinator in 2015, Ironclad has grown from a small San Francisco startup into a well-funded CLM category leader, having raised roughly $333 million across five funding rounds and reaching a $3.2 billion valuation by its Series E in 2022.$q$, $q$With over 1,000 customers and a leadership change in 2025 that brought in former DocuSign CEO Dan Springer, Ironclad continues to push further into generative AI for contracting, positioning itself against both legacy document-management vendors and newer AI-native contracting startups.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Ironclad's foundation is its structured contract repository, which stores every contract with searchable metadata and links related documents, amendments and obligations together rather than treating each contract as an isolated file. On top of the repository sits a no-code workflow designer that lets legal and business teams build custom intake, approval and negotiation workflows without engineering support, alongside native e-signature and Ironclad Clickwrap for high-volume click-to-accept agreements like terms of service.$q$, $q$The platform's AI layer applies generative AI to contract review and drafting, redlining incoming paper against a company's preferred playbook language, extracting key terms and obligations across the repository, and surfacing risk before a human reviewer sees the document, reducing the manual review burden on legal teams.$q$, $q$Ironclad also provides analytics dashboards for tracking cycle time, bottlenecks and contract volume, plus pre-built integrations with systems like Salesforce, Slack and Microsoft so that contract requests and approvals can originate from tools business teams already use, backed by SOC 2 compliance for enterprise security requirements.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Ironclad does not publish self-serve pricing and sells exclusively through a direct sales process, with tiers commonly discussed in the market as Standard, Professional and Enterprise, scaling from small legal teams of roughly 5-15 users up to enterprise deployments of 50-plus users with unlimited contract volume and dedicated account management.$q$, $q$Independent pricing-benchmark sources report typical annual contract values ranging from about $30,000 to well over $250,000 depending on company size and modules purchased, with a median reported purchase price near $39,995 per year and a minimum annual contract around $15,000; Ironclad's separately priced AI Assist module and complex system integrations can add substantially to total first-year cost.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c0335fd7-e7db-4c6c-8ece-4a1bf5b78c12', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$Drupal-based interaction layer$q$, $q$Uses Drupal's content management and theming system as the public-facing layer for browsing and managing collections.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$Fedora Commons repository$q$, $q$Stores digital objects and preservation metadata in a robust, standards-based repository layer.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$Apache Solr search$q$, $q$Provides fast full-text and faceted search and discovery across large digital collections.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$IIIF image delivery$q$, $q$Cantaloupe-powered IIIF support enables zoomable, high-resolution image viewing for manuscripts and photographs.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$Crayfish microservices$q$, $q$Decoupled services handle image and audio/video derivative generation and OCR processing.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$Flexible metadata modeling$q$, $q$Supports library and archival metadata standards such as MODS and Dublin Core.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$Batch ingest tools$q$, $q$Import large digitization backlogs in bulk rather than one object at a time.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$Community governance$q$, $q$Roadmap and releases are coordinated by the member-supported, non-profit Islandora Foundation.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$Fully open source with no license fee for the core software$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$Built on mature, widely-used components: Drupal, Fedora and Solr$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$Strong IIIF support for high-resolution image and archival media delivery$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$Community-governed model avoids single-vendor lock-in$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$Well suited to complex library and archival metadata requirements$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$Steep technical learning curve requiring Drupal and repository administration expertise$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$No official vendor support included; institutions must hire staff or contract a third party$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$Migrating between major Islandora versions can require significant re-engineering$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$Smaller ecosystem and hiring pool compared to commercial digital asset management platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$Documentation is community-maintained and can vary in completeness across modules$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$What is Islandora used for?$q$, $q$Islandora is used by libraries, archives and museums to ingest, preserve, describe and publicly expose digital collections such as scanned documents, photographs and audio-visual materials.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$Is Islandora free?$q$, $q$Yes, Islandora is fully open source and free to download, install and modify. The Islandora Foundation is supported through optional institutional membership dues, not software licensing fees.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$What technologies is Islandora built on?$q$, $q$Islandora is built on Drupal for content management, Fedora Commons for repository storage, and Apache Solr for search, with Crayfish microservices handling image and media processing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$Who created Islandora?$q$, $q$Islandora was originally developed in 2006 at the University of Prince Edward Island's Robertson Library and is now governed by the community-run Islandora Foundation.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$Does Islandora support high-resolution image viewing?$q$, $q$Yes, Islandora includes IIIF-compliant image delivery through a Cantaloupe image server, supporting zoomable, high-resolution viewers for archival images.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$What are alternatives to Islandora?$q$, $q$Common alternatives include DSpace, the Samvera/Hyrax framework, ArchivesSpace, CONTENTdm and commercial platforms like Preservica and Ex Libris Rosetta.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$Digital library collections$q$, $q$Academic libraries digitize and publish rare books, manuscripts and institutional archives with searchable metadata and IIIF viewers.$q$, $q$Academic and research libraries$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$Museum and archival collections access$q$, $q$Museums and archives use Islandora to provide public online access to photographs, artifacts and historical records.$q$, $q$Museums and archives$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$Institutional research repositories$q$, $q$Universities host theses, datasets and research outputs in a preservation-grade repository built on Fedora.$q$, $q$University research offices$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$Open Source (Self-hosted)$q$, $q$Free$q$, $q$Self-hosted, free forever$q$, NULL, $q$["Full Islandora/Drupal/Fedora/Solr stack","IIIF image delivery","Batch ingest tools","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$Foundation Membership$q$, $q$Variable dues by tier (Member, Collaborator, Partner)$q$, $q$Annual membership$q$, NULL, $q$["Voting rights in governance","Access to Foundation events","Support for roadmap and releases"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Islandora exists to solve a problem specific to libraries, archives and museums: how to ingest, describe, preserve and publicly expose large, heterogeneous digital collections -- scanned books, photographs, audio and video recordings, and research datasets -- in a system built for long-term stewardship rather than short-lived web content. Rather than building a monolithic application, Islandora combines Drupal, the Fedora Commons repository, and Apache Solr search into a single integrated framework.$q$, $q$The project began in 2006 at the University of Prince Edward Island's Robertson Library, where it was created to manage the university's own digital collections before being released as open source and adopted by institutions worldwide. Governance has since moved from the originating university to the community-run, member-supported Islandora Foundation, which coordinates the project's roadmap, releases and annual Islandoracon conference.$q$, $q$Because Islandora is fully open source, institutions can install and run it without any license fee, though most rely on either in-house technical staff or third-party vendors such as discoverygarden for hosting, migration and ongoing support, reflecting the project's community-governed, vendor-neutral model.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Islandora's architecture layers Drupal as the content management and public-facing interaction layer on top of Fedora Commons, which handles the actual storage and preservation metadata for digital objects, with Apache Solr providing fast full-text and faceted search across the collection. The current Islandora release rebuilt this on modern Drupal 9/10 and Fedora 6, connected through a set of decoupled 'Crayfish' microservices for tasks like image and audio/video derivative generation and OCR.$q$, $q$IIIF (International Image Interoperability Framework) support is built in via a Cantaloupe image server, allowing institutions to deliver high-resolution, zoomable images and interoperable viewers for manuscripts, maps and photographs, while dedicated audio and video handling supports born-digital and digitized time-based media collections.$q$, $q$Because it inherits Drupal's content-management capabilities, Islandora also offers flexible metadata modeling (supporting standards like MODS and Dublin Core), customizable theming, granular access control for restricted collections, and batch ingest tools for importing large digitization backlogs, all of which are extensible through Drupal's broader module ecosystem.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Islandora itself carries no license fee; the software, its Drupal modules, and its Crayfish microservices are all open source and free to download, install and modify. There is no tiered commercial pricing structure for the software the way there would be for a proprietary digital asset management platform.$q$, $q$Sustainability instead comes through the Islandora Foundation's membership program, which offers Member, Collaborator and Partner tiers of financial support for institutions that can afford to contribute, alongside a contributor program aimed at including organizations that cannot pay dues. Institutions that want hands-on implementation, hosting or migration support typically contract separately with third-party vendors like discoverygarden or LYRASIS rather than paying Islandora directly.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('014ca794-6131-4f44-a025-a0ff78da3c46', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$Self-hosted comment server$q$, $q$Runs entirely on infrastructure the site owner controls, with no third-party tracking or data sharing.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$SQLite storage backend$q$, $q$Stores all comments and moderation data locally in a single SQLite database file.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$Markdown comment formatting$q$, $q$Commenters can write formatted replies using Markdown syntax.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$Edit and delete window$q$, $q$Commenters can edit or delete their own comments within a configurable time window, 15 minutes by default.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$Disqus and WordPress import$q$, $q$Built-in tools migrate existing comment threads from Disqus or WordPress exports.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$Lightweight JavaScript client$q$, $q$Compact ~65KB client widget keeps page load times fast on static and lightweight sites.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$Moderation queue$q$, $q$Site administrators can approve, reject or delete comments before or after publication.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$Static site generator friendly$q$, $q$Purpose-built to add comments to Jekyll, Hugo, Pelican and other static site generator blogs.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$Completely free, open-source and self-hosted with no vendor lock-in$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$Keeps all commenter data on infrastructure the site owner controls$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$Lightweight JavaScript client keeps page load times fast$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$Built-in Disqus and WordPress import simplifies migration away from hosted platforms$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$Well suited to static site generators that lack native comment support$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$Requires self-hosting and ongoing server maintenance, unlike a managed SaaS widget$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$No official commercial support or SLA, since the project has no company behind it$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$Feature set is deliberately minimal compared to full engagement platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$Setup requires basic Python and server administration knowledge$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$Community-maintained development pace is slower than that of funded commercial alternatives$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$What is Isso?$q$, $q$Isso is a lightweight, self-hosted commenting server written in Python that serves as an open-source, privacy-friendly alternative to Disqus.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$Is Isso free?$q$, $q$Yes, Isso is completely free and open source under the MIT license. The only cost is the server infrastructure needed to self-host it.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$Who created Isso?$q$, $q$Isso was created by developer Martin Zimmermann (GitHub handle posativ) and is now maintained by the open-source community under the isso-comments GitHub organization.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$Can Isso import comments from Disqus?$q$, $q$Yes, Isso includes built-in import tools for migrating existing comment threads from Disqus and WordPress.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$Does Isso work with static site generators?$q$, $q$Yes, Isso is commonly used with static site generators like Jekyll, Hugo and Pelican, which have no native commenting system of their own.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$What database does Isso use?$q$, $q$Isso stores all comments locally in a SQLite database, keeping all data on the operator's own server.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$Static blog commenting$q$, $q$Bloggers using Jekyll, Hugo or Pelican add a self-hosted comment section without relying on a third-party widget.$q$, $q$Technical bloggers and static site owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$Privacy-focused publishing$q$, $q$Privacy-conscious publishers avoid sending visitor data to third-party advertising networks embedded in hosted comment platforms.$q$, $q$Privacy-focused website owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$Disqus migration$q$, $q$Site owners leaving Disqus over data privacy or ad-injection concerns import their existing comment history into a self-hosted Isso instance.$q$, $q$Developers migrating away from hosted comment platforms$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$Self-hosted$q$, $q$Free$q$, $q$Free forever, self-hosted$q$, NULL, $q$["Full commenting server","SQLite storage","Markdown comments","Disqus/WordPress import","Moderation queue"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Isso fills a specific niche: giving blog and static site owners a way to accept reader comments without routing visitor data through a third-party advertising and analytics company like Disqus. It runs as a small, self-hosted Python server paired with a lightweight JavaScript widget that any site can embed, regardless of what the rest of the site is built with.$q$, $q$The project was created by developer Martin Zimmermann, known online as 'posativ,' originally to serve his own blog's needs, and has since been carried forward by the open-source community, with the codebase now maintained under the isso-comments GitHub organization. It has no corporate backer and no paid tier; it is simply a free, open-source tool maintained by contributors.$q$, $q$Isso is particularly popular among users of static site generators such as Jekyll, Hugo and Pelican, which have no native way to accept dynamic comments and would otherwise need to rely on a hosted third-party widget.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, Isso is a Python server backed by SQLite, meaning every comment, reply and moderation decision is stored in a single local database file the site owner fully controls, with no data ever leaving their own server. The accompanying JavaScript client is intentionally minimal, at roughly 65KB uncompressed, keeping page weight low compared to most hosted comment widgets.$q$, $q$Isso supports Markdown formatting in comments, lets commenters edit or delete their own submissions within a configurable time window (15 minutes by default), and gives site administrators a moderation queue to approve, reject or remove comments before or after they go live, helping control spam and abuse without an external moderation service.$q$, $q$To ease migration away from hosted platforms, Isso includes built-in importers for Disqus and WordPress comment exports, so site owners switching away from a third-party service can bring their existing comment history along rather than starting from zero.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Isso itself is entirely free and open source under the MIT license; there is no license fee, subscription, or paid tier of any kind, since the project has no company or commercial arm behind it. Anyone can download the source from GitHub or install it via PyPI at no cost.$q$, $q$The only ongoing cost is whatever server infrastructure an operator chooses to run it on, since Isso must be self-hosted rather than used as a managed cloud service. In practice this typically means a small virtual private server or Docker container costing a few dollars a month, a fraction of what a hosted comment platform with a paid tier would charge, especially for sites with any meaningful comment volume.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('45e476ca-e137-4841-abde-19c6273464c0', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
