INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fc7d423-2bfb-4923-85a9-5d419bf4c26f', $q$What is Iterable used for?$q$, $q$Iterable is used to orchestrate personalized, cross-channel marketing campaigns and customer journeys across email, SMS, push notifications, in-app messages and direct mail.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fc7d423-2bfb-4923-85a9-5d419bf4c26f', $q$Who founded Iterable?$q$, $q$Iterable was founded in San Francisco in 2013 by former Twitter engineer Justin Zhu and former Google engineer Andrew Boni.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fc7d423-2bfb-4923-85a9-5d419bf4c26f', $q$How much does Iterable cost?$q$, $q$Iterable does not publish pricing; it is sold through an enterprise sales process priced mainly on monthly active users, with typical annual costs ranging from around $36,000 for small deployments to $200,000-plus for large enterprise programs.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fc7d423-2bfb-4923-85a9-5d419bf4c26f', $q$Does Iterable use AI?$q$, $q$Yes, Iterable's Nova Intelligence suite includes Nova Agent for autonomous campaign building, Brand Affinity scoring, Predictive Goals, Send Time Optimization and AI-assisted copywriting.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fc7d423-2bfb-4923-85a9-5d419bf4c26f', $q$Who are Iterable's main competitors?$q$, $q$Iterable's main competitors include Braze, Klaviyo, Salesforce Marketing Cloud, Airship and MoEngage.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fc7d423-2bfb-4923-85a9-5d419bf4c26f', $q$Is Iterable a public company?$q$, $q$No, Iterable remains a privately held company as of 2026, having last raised a $200 million Series E round in 2021 at a roughly $2 billion valuation.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5fc7d423-2bfb-4923-85a9-5d419bf4c26f', $q$Lifecycle marketing automation$q$, $q$Consumer brands build automated, multi-step customer journeys that adapt in real time based on user behavior across channels.$q$, $q$Enterprise marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5fc7d423-2bfb-4923-85a9-5d419bf4c26f', $q$Mobile app engagement$q$, $q$Gaming and app-first companies use push and in-app messaging to re-engage users based on predicted churn risk.$q$, $q$Mobile app and gaming companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5fc7d423-2bfb-4923-85a9-5d419bf4c26f', $q$Personalized promotional campaigns$q$, $q$Retail and e-commerce brands personalize email and SMS promotions per user using Brand Affinity and predictive scoring.$q$, $q$Retail and e-commerce marketing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5fc7d423-2bfb-4923-85a9-5d419bf4c26f', $q$Growth$q$, $q$Custom pricing (est. $36,000-$72,000/year for SMB)$q$, $q$Annual contract$q$, NULL, $q$["Core channels: email, SMS, push","Basic segmentation","Workflow automation"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5fc7d423-2bfb-4923-85a9-5d419bf4c26f', $q$Premier$q$, $q$Custom pricing (est. $72,000-$180,000/year)$q$, $q$Annual contract$q$, NULL, $q$["All Growth features","Additional channels","Advanced AI features","Higher support tier"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5fc7d423-2bfb-4923-85a9-5d419bf4c26f', $q$Enterprise$q$, $q$Custom pricing (est. $200,000-plus/year)$q$, $q$Annual contract$q$, NULL, $q$["All Premier features","Full Nova Intelligence AI suite","Dedicated support and onboarding","Highest MAU and channel limits"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5fc7d423-2bfb-4923-85a9-5d419bf4c26f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Iterable positions itself as a unified control center for customer engagement, replacing the separate email service provider, push notification tool, SMS platform and in-app messaging system that many marketing teams historically stitched together. Every channel is driven from the same underlying customer data and the same visual journey builder, so a single automated program can email a user, follow up with a push notification if they don't open it, and escalate to SMS if neither lands.$q$, $q$The company was founded in San Francisco in 2013 by former Twitter engineer Justin Zhu and former Google engineer Andrew Boni, and grew into a well-funded category leader, raising roughly $342 million in venture capital and reaching unicorn status with a roughly $2 billion valuation after its 2021 Series E led by Silver Lake.$q$, $q$Iterable remains privately held as of 2026, with several hundred to just over a thousand employees globally, and has increasingly positioned generative AI, branded as Nova Intelligence, as its primary differentiator against rivals like Braze and Klaviyo.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5fc7d423-2bfb-4923-85a9-5d419bf4c26f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Iterable's core is Studio, a visual, drag-and-drop journey builder that lets marketers design event-triggered, branching customer journeys with built-in A/B and multivariate testing, spanning email, SMS, mobile and web push, in-app messaging and direct mail from one interface. Campaigns pull directly from synced customer and event data, allowing highly granular audience segmentation without engineering involvement for most day-to-day campaign work.$q$, $q$The platform's Nova Intelligence AI suite adds Nova Agent for autonomous campaign building, QA and optimization; Brand Affinity scoring that predicts each user's preferred channel and content; Predictive Goals for forecasting churn and conversion likelihood; Send Time Optimization; and AI-assisted copywriting, collectively aimed at reducing manual campaign configuration while improving per-user personalization.$q$, $q$A 2026-era addition, Iterable Command Center, gives marketing leaders a centralized, goal-based performance view across every active campaign and journey, while the platform's broader ecosystem includes integrations with customer data platforms, data warehouses like Snowflake, and CRM systems like Salesforce for keeping customer data continuously in sync.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5fc7d423-2bfb-4923-85a9-5d419bf4c26f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Iterable does not offer self-serve, publicly listed pricing; the platform is sold through an enterprise sales process with cost driven primarily by monthly active users (MAUs) contacted across channels, plus which channels and AI features a customer licenses. Publicly referenced tiers include Growth, Premier and Enterprise, moving from core email/SMS/push functionality up to the full channel and AI feature set with higher-touch support.$q$, $q$Third-party benchmark data suggests entry-level and SMB deployments typically run from about $36,000 to $72,000 per year, mid-market programs from roughly $72,000 to $180,000, and large enterprise programs $200,000 and up, with SMS and push notification usage frequently carrying additional per-message or per-user fees layered on top of the base MAU-driven subscription.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5fc7d423-2bfb-4923-85a9-5d419bf4c26f', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
