INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$Low-code data model designer$q$, $q$Add custom configuration item classes, fields and relationships without writing PHP code.$q$, 2);
