INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$SLA management$q$, $q$Configure and track response and resolution targets against service level agreements.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$REST/JSON API$q$, $q$Integrate iTop with monitoring tools, directories and other IT systems via a web services API.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$Knowledge base$q$, $q$Built-in knowledge base for documenting solutions and reducing repeat tickets.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$iTop Hub extensions$q$, $q$Marketplace of Combodo and community-built add-ons and integrations extending the core platform.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$Community edition is genuinely free and open source with no artificial feature limits$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$Deep CMDB customization through a no-code/low-code data model designer$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$Covers full ITIL service management workflow, not just asset tracking$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$AGPL-3.0 license guarantees source transparency and prevents vendor lock-in$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$French, Europe-based vendor appealing to organizations wanting data sovereignty$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$Community edition is best suited to small teams of around 10 agents or fewer$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$Paid Atelier and Forge editions do not publish pricing, requiring a sales conversation$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$User interface feels dated compared to newer SaaS-native ITSM competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$Requires self-hosting expertise for organizations not using the SaaS option$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$Smaller partner and integration ecosystem than category leaders like ServiceNow$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$Is iTop free?$q$, $q$Yes, iTop Community is a free, open-source edition under the AGPL-3.0 license, best suited to teams of around 10 agents or fewer. Larger teams can upgrade to the paid Atelier or Forge editions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$Who develops iTop?$q$, $q$iTop is developed by Combodo, a French software company founded in Grenoble in 2010 by Erwan Taloc, Denis Flaven and Romain Quetiez.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$What is iTop used for?$q$, $q$iTop is used for IT service management and configuration management, covering incident, problem, change and request management alongside a customizable CMDB.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$Does iTop have an API?$q$, $q$Yes, iTop provides a REST/JSON web services API for integrating with monitoring tools, LDAP directories, SSO and other IT systems.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$What are the paid editions of iTop?$q$, $q$Combodo sells iTop Atelier for teams up to roughly 50 agents and iTop Forge for larger, more customized deployments of 50-plus agents; both are available on-premise or as SaaS with quote-based pricing.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$What are alternatives to iTop?$q$, $q$Common alternatives include GLPI, ServiceNow, Jira Service Management, SysAid and Ivanti Neurons for ITSM.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$Small IT team service desk$q$, $q$Small internal IT departments run the free Community edition to manage tickets, assets and changes without licensing cost.$q$, $q$Small internal IT teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$Managed service provider operations$q$, $q$MSPs use iTop's multi-tenant capabilities and CMDB to manage IT assets and tickets across multiple client organizations.$q$, $q$Managed service providers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$Enterprise ITIL service management$q$, $q$Larger organizations adopt iTop Atelier or Forge for a fully supported, ITIL-certified service management deployment.$q$, $q$Enterprise IT operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$Community$q$, $q$Free$q$, $q$Free forever, self-hosted$q$, NULL, $q$["Full CMDB and ITIL service management","Recommended for up to ~10 agents","On-premise deployment","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$Atelier$q$, $q$Custom pricing (contact Combodo)$q$, $q$Annual, on-premise or SaaS$q$, NULL, $q$["Up to ~50 agents","Operational-level ITIL support","On-premise or SaaS deployment"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$Forge$q$, $q$Custom pricing (contact Combodo)$q$, $q$Annual, on-premise or SaaS$q$, NULL, $q$["50-plus agents","Fully industrialized, custom deployment","Expert support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$iTop is designed to give IT operations teams a single, web-based system for tracking both what their IT environment consists of (through its CMDB) and how they operate and support it (through ITIL-aligned incident, problem, change and request management). Rather than treating asset tracking and service desk ticketing as separate tools, iTop ties them together so, for example, an incident ticket can be directly linked to the specific server or application configuration item it affects.$q$, $q$The platform is developed by Combodo, a French software company founded in Grenoble in 2010 by Erwan Taloc, Denis Flaven and Romain Quetiez, and now based in Echirolles near Grenoble. Combodo has grown iTop to more than 2,900 organizations worldwide while remaining a relatively small, focused team of roughly 11 to 50 employees.$q$, $q$iTop's core is released under the AGPL-3.0 open-source license and can be freely downloaded, self-hosted and modified, with Combodo generating revenue instead from paid, supported editions (Atelier and Forge) and professional services for organizations that want a managed or heavily customized deployment.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At the heart of iTop is its CMDB, which tracks IT assets -- servers, applications, network devices, and the relationships and dependencies between them -- giving support teams visibility into what an incident or change might impact before they act. This CMDB is fully customizable through iTop's low-code data model designer, which lets administrators add new object classes, fields and relationships without writing PHP code.$q$, $q$On the service management side, iTop covers the core ITIL processes: incident management, problem management, change management, and a self-service portal where end users can submit and track their own requests, backed by a knowledge base and configurable SLA tracking for measuring response and resolution performance against targets.$q$, $q$Extensibility comes through a REST/JSON API for integrating with monitoring tools, LDAP directories and SSO providers, plus 'iTop Hub,' a community and Combodo-maintained marketplace of add-ons and extensions that plug additional functionality -- from specific integrations to industry-specific workflows -- into the core platform without forking the codebase.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e7979bb4-e11f-4629-ba03-f702582d77cc', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$iTop Community, the free open-source edition, is unrestricted and recommended for teams of roughly 10 or fewer agents running the platform on-premise; there is no license fee and no artificial feature-gating built into the free tier. This makes iTop one of the few genuinely full-featured, no-cost ITSM platforms available for small IT teams.$q$, $q$For larger deployments, Combodo sells iTop Atelier (targeting teams up to roughly 50 agents, available on-premise or as SaaS) and iTop Forge (targeting 50-plus agents needing deep customization and industrialized support, also on-premise or SaaS), but neither edition's pricing is published; both require contacting Combodo directly for a custom quote based on agent count, deployment model and support level.$q$]::text[], 2);
