-- ── ioBroker ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source, self-hosted integration platform for connecting smart home, building automation and IoT devices under one system.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (optional paid ioBroker.pro cloud subscription)$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$ioBroker Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$ioBroker review 2026: a deep dive into this open-source home and building automation integration platform, its adapters, self-hosting setup and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$ioBroker is a free, open-source integration platform for the Internet of Things that lets users connect and automate smart home devices, building automation systems, energy meters, and industrial process data from a single self-hosted server. Its roots trace back to CCU.IO, a popular tool in the German HomeMatic smart-home community, from which ioBroker emerged as a spin-off around 2014, developed primarily by Denis Haev, who goes by the online handle 'Bluefox' and remains the project's core maintainer, main developer and managing director of ioBroker GmbH, the small commercial entity that holds the ioBroker trademark and funds infrastructure such as the website, forum, and download servers. ioBroker GmbH operates with essentially one full-time employee (Bluefox himself) supported by a large volunteer contributor community, and is funded through a mix of external commercial development contracts and an optional paid cloud service, ioBroker.pro, rather than through venture capital. Architecturally, ioBroker is written in JavaScript and runs on Node.js, making it deployable on a Raspberry Pi, a Docker container, or any Linux, Windows or macOS machine with at least 1GB of RAM. Its core is the js-controller, a central coordinator process that manages a modular ecosystem of more than 1,000 community-built 'adapters' -- plugins that each speak to a specific device, protocol or service, covering smart home standards like KNX, Zigbee, Z-Wave and Homematic, cloud ecosystems like Amazon Alexa, Google Home and Sonos, and generic protocols like MQTT, Modbus and OPC-UA. Automation logic is configured through the built-in Admin web interface, a JavaScript-based scripting adapter (Blockly or native JS), and the VIS visualization module, which lets users build custom dashboards for monitoring and controlling connected devices without writing full applications. The bulk of ioBroker -- the js-controller and the vast majority of adapters -- is released as open-source software under the MIT license, meaning it can be installed, modified and run entirely for free and with full data ownership, since everything operates locally on the user's own hardware rather than through a third-party cloud. A handful of components require a free license issued by ioBroker GmbH for private, non-commercial use, primarily to track usage and fund upkeep of the wider project, while ioBroker.pro offers a paid, hosted convenience layer (remote access, backups and simplified server management) for users who don't want to self-host the underlying server. ioBroker's target audience is technically inclined home automation enthusiasts, hobbyists and small integrators, particularly within the German-speaking DIY smart-home community where it originated and remains most popular, though its adapter catalog and documentation have since expanded to a broader international, primarily English- and German-speaking user base. It competes most directly with Home Assistant, the dominant open-source home automation platform with a larger global community and Python-based architecture, as well as with openHAB, another Java-based open-source integration hub, and with proprietary hub ecosystems like Samsung SmartThings or Homey. ioBroker differentiates itself through its deep roots in and support for German building-automation and metering standards, its lightweight Node.js footprint suitable for low-powered hardware, and a governance model that keeps the core project free and self-hosted while funding development through a light commercial layer rather than advertising, data monetization or a hard paywall.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '040370f5-8835-4009-88cd-4a1d8b345969';

