-- ── iRedMail ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source installer that deploys a complete, self-hosted mail server with webmail, groupware and anti-spam in minutes.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid iRedAdmin-Pro panel and iRedMail Easy hosting available)$q$, starting_price),
  founded_year = COALESCE(2007, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$Chinese$q$]::text[],
  seo_title = COALESCE($q$iRedMail Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$iRedMail review 2026: an in-depth look at this open-source mail server installer, its architecture, editions, pricing and top self-hosted alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$iRedMail is a free, open-source shell-script installer that assembles a complete, production-ready mail server on a single Linux or BSD machine by combining and pre-configuring a stack of well-known open-source mail components, so administrators don't have to manually integrate Postfix, Dovecot, a directory or database backend, webmail, and anti-spam tooling from scratch. The project was started in November 2007 by developer Zhang Huangbin, who remains its primary author and maintainer, and who built iRedMail to solve the recurring pain of manually wiring together a mail server's many moving parts -- a process that historically took experienced sysadmins days to get right and secure. Architecturally, iRedMail deploys Postfix as the SMTP transport, Dovecot for POP3/IMAP, and gives administrators a choice of backend for accounts and domains: OpenLDAP, MySQL/MariaDB, or PostgreSQL. On top of that it layers Roundcube webmail and/or the SOGo groupware suite (for shared calendars, address books and tasks via CalDAV/CardDAV, plus ActiveSync for mobile), Amavisd, SpamAssassin and ClamAV for anti-spam and anti-virus filtering, OpenDKIM and SPF for outbound authentication, Fail2ban for intrusion prevention, and iRedAPD as a Postfix policy daemon for advanced sender restrictions. All mail-in-transit is enforced over TLS, and the finished install is designed to be 'secure by default,' with SSHA512/BCRYPT password hashing and mail quarantine built in. iRedMail supports mainstream Linux and BSD distributions including CentOS Stream, Rocky Linux, AlmaLinux, Debian, Ubuntu, FreeBSD and OpenBSD, and is released and distributed under the GPLv3 open-source license, meaning the core installer and resulting mail server are entirely free to download, run, and modify, with unlimited domains, users and mailing lists. The project sustains itself commercially through two optional paid products layered on top of the free base: iRedAdmin-Pro, a full-featured web-based administration panel (the free edition bundled with iRedMail is deliberately limited) priced as a license with an annual renewal fee reported around $250/year for continued updates and support, and iRedMail Easy, a web-based deployment and support platform that helps less experienced administrators stand up and maintain their own iRedMail server, priced at roughly $499/year or about $49/month on a 12-month plan. Because everything runs on infrastructure the customer owns, there is no per-mailbox SaaS fee and no vendor lock-in, which is the core value proposition against hosted email services. iRedMail's target audience is systems administrators, small businesses, hosting providers, privacy-focused organizations and self-hosting enthusiasts who want full ownership of their email infrastructure and data rather than relying on Google Workspace, Microsoft 365, or a managed IMAP host. Its direct open-source competitors include Mail-in-a-Box, Mailcow, Modoboa, and Zimbra's community edition, as well as the older Postfix Admin project, with iRedMail differentiating itself through its especially broad distribution support, choice of LDAP/SQL backend, long track record dating back to 2007, and its optional paid support tier for organizations that want the reliability of a maintained open-source stack without paying recurring per-seat SaaS pricing.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ba51550d-a30f-4ff6-991a-d6db68d152ca';

