-- ── Islandora ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source digital repository framework built on Drupal and Fedora for managing and preserving digital collections.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (optional Islandora Foundation membership dues for organizations)$q$, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Islandora Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Islandora review 2026: a deep dive into this open-source digital repository framework built on Drupal and Fedora, its features, governance and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Islandora is a free, open-source digital asset management and repository framework used primarily by libraries, archives, museums and other cultural heritage and research institutions to ingest, preserve, describe and provide public access to digitized collections such as scanned manuscripts, photographs, audio, video and research datasets. The project originated in 2006 at the University of Prince Edward Island's Robertson Library in Canada, where library staff, led by figures including Mark Leggott, built the first version to manage the university's own growing digital collections; the software was subsequently open-sourced and adopted by other institutions, and the university's technology transfer led to the founding of discoverygarden inc., a commercial support and hosting company for Islandora based in Charlottetown, PEI. As adoption spread beyond UPEI, governance of the project transitioned to the community, and today Islandora is stewarded by the Islandora Foundation, a member-supported non-profit organization that coordinates roadmap decisions, releases and community events (including the annual Islandoracon conference) on behalf of the global institutions running the software, rather than by any single vendor. Technically, Islandora is a 'glue' framework that combines several independent open-source systems rather than reinventing them: Drupal serves as the content management and user-facing interaction layer, Fedora Commons acts as the underlying repository that stores digital objects and their preservation metadata, and Apache Solr powers full-text and faceted search and discovery across the collection. The current major version, Islandora 8 (branded simply 'Islandora' going forward), rebuilt the stack on modern Drupal (9/10), Fedora 6, and a set of decoupled microservices known as Crayfish that handle tasks like image derivative generation via a Cantaloupe IIIF image server, audio/video processing, and OCR, communicating over an ActiveMQ message queue; this modular, IIIF-compliant architecture lets institutions plug in high-resolution zoomable image viewers and time-based media players for archival AV content. Because Islandora is entirely open source (its components carry standard open-source licenses such as the GPL and MIT, consistent with Drupal's licensing), there is no software cost to download, install or modify it; the Islandora Foundation instead sustains itself through a tiered membership model -- Member, Collaborator and Partner classes, alongside a contributor program for individuals and institutions unable to pay dues -- with suggested annual contributions historically in the hundreds of dollars for community-affiliated groups, while institutions that want hosting, migration or custom development support typically contract with third-party vendors such as discoverygarden, LYRASIS, or Common Media rather than paying Islandora itself. Islandora's core audience is academic and public libraries, museums, archives and government agencies running institutional repositories, digital library programs or born-digital preservation initiatives, particularly organizations that already use or are comfortable with Drupal. Its main competitors in the digital repository and digital asset management space include DSpace (a similarly open-source institutional repository platform popular for research output), the Samvera/Hyrax framework (a Ruby-on-Rails-based repository system with a similar community-governance model), ArchivesSpace for archival description, CONTENTdm from OCLC, and commercial platforms like Preservica and Ex Libris Rosetta; Islandora differentiates itself through its tight integration with Drupal's flexible content-management and theming capabilities, its IIIF-native image and AV delivery, and its fully community-governed, vendor-neutral open-source model.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '014ca794-6131-4f44-a025-a0ff78da3c46';

