-- ── Iterable ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$AI-powered cross-channel customer engagement platform for orchestrating personalized email, SMS, push and in-app campaigns.$q$, short_description),
  pricing_model = COALESCE($q$Enterprise$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing (quote-based, scales with monthly active users)$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$501-1000 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Iterable Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Iterable review 2026: a detailed look at this AI-powered cross-channel marketing platform, its features, pricing tiers and top alternatives like Braze.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Iterable is an enterprise customer engagement and cross-channel marketing platform that lets brands orchestrate personalized campaigns and automated customer journeys across email, SMS, push notifications, in-app messages, web and direct mail from a single system. The company was founded in San Francisco in 2013 by Justin Zhu, a former Twitter engineer, and Andrew Boni, a former Google engineer, who built Iterable to give marketing teams the kind of granular, data-driven, cross-channel orchestration that had previously required stitching together separate point tools for each channel. Iterable has raised a total of roughly $342 million in venture funding, with its largest round a $200 million Series E in June 2021 led by Silver Lake and Adams Street Partners, a raise that pushed the company's valuation to around $2 billion and made it a unicorn; Iterable remains a private company as of 2026, with no announced IPO timeline, and has grown to an employee base in the 500 to 1,000-plus range spread across offices on multiple continents. Technically, Iterable is built around a customer data-driven architecture: marketers upload or sync user and event data (often via a customer data platform, data warehouse, or direct API/SDK integration), build segments from that data, and design multi-step customer journeys in Studio, Iterable's visual, drag-and-drop workflow canvas that supports event-triggered automation, branching logic, time-based scheduling and A/B/multivariate testing. Campaigns and journeys can span email, SMS, mobile and web push notifications, in-app messages, and direct mail, all coordinated from the same platform so a customer's experience stays consistent regardless of channel. In 2025 and 2026 Iterable significantly expanded its generative AI capabilities under the 'Nova Intelligence' banner, including Nova Agent, an autonomous AI agent that can build, QA and optimize campaigns with reduced manual input; Brand Affinity scoring, which predicts each individual user's preferred channel and content type; Predictive Goals, which forecasts churn risk and conversion likelihood per user; Send Time Optimization; and AI-assisted copywriting, alongside a 2026-era Iterable Command Center that gives marketers a centralized, goal-based view of campaign performance across the whole program. Iterable does not publish self-serve pricing; the platform is sold through an enterprise sales process with pricing based primarily on monthly active users (MAUs) contacted across channels, along with which channels (email, SMS, push, in-app) and features a customer licenses. Publicly discussed tiers include Growth, Premier and Enterprise, with Growth aimed at teams just starting cross-channel marketing (core channels, basic segmentation and workflow automation) and Premier/Enterprise unlocking additional channels, advanced AI features and higher support levels; third-party pricing-benchmark sources estimate typical costs from roughly $36,000 to $72,000 per year for entry-level/SMB deployments, $72,000 to $180,000 for mid-market, and $200,000-plus for large enterprise programs, with SMS and push often carrying additional usage-based fees on top of the base MAU pricing. Iterable's target customers are mid-market to enterprise marketing teams at consumer brands in retail, media, gaming, fintech and travel that need to run sophisticated, data-rich, multi-channel lifecycle marketing programs rather than simple batch-and-blast email campaigns. Its most direct competitors are Braze (its closest rival in mobile-first, enterprise cross-channel engagement), Klaviyo (stronger in e-commerce/Shopify-centric email and SMS), Salesforce Marketing Cloud (broader CRM-integrated suite), Airship and MoEngage (mobile engagement specialists), and Customer.io (mid-market-focused workflow automation); Iterable differentiates itself through its emphasis on marketer-controlled, data-driven segmentation without requiring heavy engineering support, combined with its aggressive recent investment in generative AI for autonomous campaign building and per-user channel/content personalization.$q$, llm_readable_summary),
  updated_at = now()
WHERE id = '5fc7d423-2bfb-4923-85a9-5d419bf4c26f';

