-- ── iTop ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source ITSM and CMDB platform by Combodo for managing incidents, changes, service requests and IT assets.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (Community edition); paid Atelier and Forge editions quote-based$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Grenoble/Echirolles, France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$iTop Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$iTop review 2026: an in-depth look at this open-source ITSM and CMDB platform by Combodo, its features, editions, pricing and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$iTop, short for 'IT Operations Portal,' is an open-source IT service management (ITSM) and configuration management database (CMDB) platform developed by Combodo, a software company founded in 2010 in the Grenoble region of France (based in Echirolles) by three co-founders: Erwan Taloc, Denis Flaven and Romain Quetiez. Combodo built iTop as a web-based, ITIL-aligned platform that lets IT teams manage their entire operational stack -- incidents, problems, changes, service requests and the underlying configuration items that make up their IT environment -- from a single, self-hostable application, and has grown the product to more than 2,900 organizations using it worldwide as of recent company reporting, while Combodo itself remains a relatively small company of roughly 11 to 50 employees. Technically, iTop combines a fully customizable CMDB (which auto-discovers and tracks servers, applications, network devices and their interdependencies) with an ITIL-oriented service desk covering incident management, problem management, change management, and a self-service portal for end users to submit and track requests, plus a built-in knowledge base and SLA management for tracking response and resolution commitments. A distinguishing feature is iTop's low-code data model designer, which lets administrators customize or extend the underlying object model (adding new configuration item classes, custom fields or relationships) without needing to write PHP code, alongside a REST/JSON web services API for integrating with monitoring tools, directory services (LDAP/SSO), and other IT systems. The community/core edition of iTop is released as free and open-source software, distributed under the AGPL-3.0 license (the GNU Affero General Public License), meaning the source is publicly available on GitHub, can be freely self-hosted, and any modified version made available over a network must also share its source, which Combodo has said is deliberately structured to prevent the software from being closed off by third-party resellers. On top of the free Community edition (recommended for teams of roughly 10 or fewer agents, available on-premise), Combodo sells two paid editions: iTop Atelier, aimed at growing teams (up to roughly 50 agents) needing an ITIL-tailored, operationally supported deployment available both on-premise and as SaaS, and iTop Forge, aimed at large organizations (50-plus agents) that need a fully industrialized, deeply customized deployment with expert support, also available on-premise or as SaaS; neither Atelier's nor Forge's pricing is published, and interested customers must contact Combodo directly for a quote. iTop's extensibility is further supported by 'iTop Hub,' a marketplace/community toolset of add-ons, extensions and integrations built by Combodo and third-party contributors that plug into the core platform. iTop's target audience is IT operations and support teams, from small internal IT departments running the free Community edition to managed service providers (MSPs) and larger enterprises that adopt Atelier or Forge for multi-tenant, ITIL-certified service management with vendor support. Its main competitors include GLPI (another French open-source ITSM/asset-management tool, iTop's closest direct rival), ServiceNow and Jira Service Management (enterprise-grade, much higher-cost proprietary platforms), SysAid, and Ivanti Neurons for ITSM; iTop differentiates itself through its combination of a genuinely free, unrestricted open-source core, deep CMDB customization via its low-code data model designer, and its France-based, ITIL-focused development team, appealing especially to European organizations and MSPs that want data sovereignty and full source-code transparency without sacrificing enterprise ITSM functionality.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e7979bb4-e11f-4629-ba03-f702582d77cc';

